// Parse incoming conversion event from dealer website
const input = $input.first().json;
const body = input.body || input;

// Extract event data
const event_name = body.event_name || 'Lead';
const validEvents = ['Lead', 'ViewContent', 'Schedule', 'Purchase', 'Contact', 'SubmitApplication', 'Search'];
if (!validEvents.includes(event_name)) {
  throw new Error(`Invalid event_name: ${event_name}. Must be one of: ${validEvents.join(', ')}`);
}

// Extract user data (raw — will be hashed in next node)
const user_data = body.user_data || {};
const email = user_data.email || user_data.em || null;
const phone = user_data.phone || user_data.ph || null;
const client_ip_address = user_data.client_ip_address || input.headers?.['x-forwarded-for'] || input.headers?.['x-real-ip'] || null;
const client_user_agent = user_data.client_user_agent || input.headers?.['user-agent'] || null;
const fbc = user_data.fbc || body.fbc || null;
const fbp = user_data.fbp || body.fbp || null;
const external_id = user_data.external_id || body.lead_id || null;

// Extract custom data
const custom_data = body.custom_data || {};
const vehicle_make = custom_data.vehicle_make || null;
const vehicle_model = custom_data.vehicle_model || null;
const value = custom_data.value ? parseFloat(custom_data.value) : null;
const currency = custom_data.currency || 'CAD';
const content_name = custom_data.content_name || (vehicle_make && vehicle_model ? `${vehicle_make} ${vehicle_model}` : null);
const content_category = custom_data.content_category || 'vehicle';

// Event source URL
const event_source_url = body.event_source_url || input.headers?.referer || null;

// Event ID for deduplication (browser + server events)
const event_id = body.event_id || `srv_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

return [{
  json: {
    event_name,
    event_id,
    event_time: Math.floor(Date.now() / 1000),
    event_source_url,
    user_data: {
      email,
      phone,
      client_ip_address,
      client_user_agent,
      fbc,
      fbp,
      external_id
    },
    custom_data: {
      vehicle_make,
      vehicle_model,
      value,
      currency,
      content_name,
      content_category
    }
  }
}];

// SHA256 hash PII fields per Meta Conversions API requirements
// Meta requires: lowercase, trimmed, then SHA256 hashed
const crypto = require('crypto');

function sha256Hash(value) {
  if (!value) return null;
  const normalized = String(value).toLowerCase().trim();
  if (!normalized) return null;
  // If already hashed (64 hex chars), pass through
  if (/^[a-f0-9]{64}$/.test(normalized)) return normalized;
  return crypto.createHash('sha256').update(normalized).digest('hex');
}

function normalizePhone(phone) {
  if (!phone) return null;
  let digits = String(phone).replace(/\D/g, '');
  if (digits.length === 10) digits = '1' + digits;
  return digits;
}

const input = $input.first().json;
const userData = input.user_data;

const hashedEmail = sha256Hash(userData.email);
const normalizedPhone = normalizePhone(userData.phone);
const hashedPhone = sha256Hash(normalizedPhone);
const hashedExternalId = sha256Hash(userData.external_id);

return [{
  json: {
    ...input,
    user_data: {
      em: hashedEmail ? [hashedEmail] : [],
      ph: hashedPhone ? [hashedPhone] : [],
      client_ip_address: userData.client_ip_address,
      client_user_agent: userData.client_user_agent,
      fbc: userData.fbc,
      fbp: userData.fbp,
      external_id: hashedExternalId ? [hashedExternalId] : []
    },
    _hashing: {
      email_provided: !!userData.email,
      phone_provided: !!userData.phone,
      external_id_provided: !!userData.external_id
    }
  }
}];

// Build Meta Conversions API payload
const input = $input.first().json;

const event = {
  event_name: input.event_name,
  event_time: input.event_time,
  event_id: input.event_id,
  action_source: 'website',
  user_data: {}
};

const ud = input.user_data;
if (ud.em && ud.em.length > 0) event.user_data.em = ud.em;
if (ud.ph && ud.ph.length > 0) event.user_data.ph = ud.ph;
if (ud.client_ip_address) event.user_data.client_ip_address = ud.client_ip_address;
if (ud.client_user_agent) event.user_data.client_user_agent = ud.client_user_agent;
if (ud.fbc) event.user_data.fbc = ud.fbc;
if (ud.fbp) event.user_data.fbp = ud.fbp;
if (ud.external_id && ud.external_id.length > 0) event.user_data.external_id = ud.external_id;

if (input.event_source_url) event.event_source_url = input.event_source_url;

const cd = input.custom_data;
const customData = {};
if (cd.vehicle_make) customData.vehicle_make = cd.vehicle_make;
if (cd.vehicle_model) customData.vehicle_model = cd.vehicle_model;
if (cd.value !== null && cd.value !== undefined) customData.value = cd.value;
if (cd.currency) customData.currency = cd.currency;
if (cd.content_name) customData.content_name = cd.content_name;
if (cd.content_category) customData.content_category = cd.content_category;

if (Object.keys(customData).length > 0) event.custom_data = customData;

const hasUserData = Object.keys(event.user_data).length > 0;
if (!hasUserData) {
  throw new Error('At least one user_data field required (email, phone, IP, user agent, fbc, or fbp)');
}

const payload = { data: [event] };

const pixelId = $env.META_PIXEL_ID;
const accessToken = $env.META_ACCESS_TOKEN;
if (!pixelId || !accessToken) {
  throw new Error('META_PIXEL_ID and META_ACCESS_TOKEN environment variables are required');
}

const apiUrl = `https://graph.facebook.com/v19.0/${pixelId}/events?access_token=${accessToken}`;

return [{
  json: {
    payload,
    apiUrl,
    _meta: {
      event_name: input.event_name,
      event_id: input.event_id,
      user_data_fields: Object.keys(event.user_data),
      custom_data_fields: Object.keys(customData),
      hashing: input._hashing
    }
  }
}];

// Log successful Meta CAPI event submission
const response = $input.first().json;
const meta = $('Build CAPI Payload').first().json._meta;

const result = {
  status: 'SUCCESS',
  timestamp: new Date().toISOString(),
  event_name: meta.event_name,
  event_id: meta.event_id,
  user_data_fields: meta.user_data_fields,
  custom_data_fields: meta.custom_data_fields,
  hashing: meta.hashing,
  meta_response: {
    events_received: response.body?.events_received || response.events_received || null,
    messages: response.body?.messages || response.messages || [],
    fbtrace_id: response.body?.fbtrace_id || response.fbtrace_id || null,
    http_status: response.statusCode || 200
  }
};

console.log(`[META-CAPI] SUCCESS: ${meta.event_name} (${meta.event_id}) — events_received: ${result.meta_response.events_received}`);

return [{
  json: {
    success: true,
    event_id: meta.event_id,
    event_name: meta.event_name,
    events_received: result.meta_response.events_received,
    timestamp: result.timestamp
  }
}];

// Dead letter handler for failed Meta CAPI submissions
const error = $input.first().json;
const meta = $('Build CAPI Payload').first().json._meta || {};
const payload = $('Build CAPI Payload').first().json.payload || {};

const deadLetter = {
  status: 'FAILED',
  timestamp: new Date().toISOString(),
  event_name: meta.event_name || 'unknown',
  event_id: meta.event_id || 'unknown',
  error: {
    message: error.message || error.error?.message || 'Unknown error',
    statusCode: error.statusCode || error.code || null,
    meta_error: error.body?.error || error.error || null
  },
  original_payload: payload,
  retry_info: {
    max_retries: 3,
    all_retries_exhausted: true
  }
};

console.error(`[META-CAPI] FAILED: ${deadLetter.event_name} (${deadLetter.event_id}) — ${deadLetter.error.message}`);

const staticData = $getWorkflowStaticData('global');
if (!staticData.deadLetterQueue) staticData.deadLetterQueue = [];
staticData.deadLetterQueue.push(deadLetter);
if (staticData.deadLetterQueue.length > 100) {
  staticData.deadLetterQueue = staticData.deadLetterQueue.slice(-100);
}

return [{
  json: {
    success: false,
    event_id: deadLetter.event_id,
    event_name: deadLetter.event_name,
    error: deadLetter.error.message,
    timestamp: deadLetter.timestamp,
    queued_for_retry: true
  }
}];
